// @category: baseline
struct TreeNode { int val; struct TreeNode* left; struct TreeNode* right; }; struct TreeNode* createNode(int val) { struct TreeNode* node = (struct TreeNode*)malloc(sizeof(struct TreeNode)); node->val = val; node->left = NULL; node->right = NULL; return node; } struct TreeNode* insert(struct TreeNode* root, int val) { if (root == NULL) return createNode(val); if (val < root->val) root->left = insert(root->left, val); else root->right = insert(root->right, val); return root; } struct TreeNode* search(struct TreeNode* root, int key) { if (root == NULL || root->val == key) return root; if (key < root->val) return search(root->left, key); else return search(root->right, key); } int main() { struct TreeNode* root = NULL; root = insert(root, 5); insert(root, 3); insert(root, 7); struct TreeNode* res = search(root, 7); printf("%d", res->val); return 0; }
